        "Id","Name","Sku","Description","CategoryId","CostPrice","SalePrice","SuggestedPrice","ProfitMargin","CurrentStock","MinimumStock",
        "ItemsPerPlate","EstimatedPrintTimeMinutes","EstimatedWeightGrams","LengthMetersUsed","TariffPerKwh","FinishingPercentage","PrinterProfileId","FilamentProfileId",
        "DefaultMarketplaceFeeId","CreatedAtUtc","UpdatedAtUtc")
    SELECT
        sp.id,
        sp.name,
        sp.sku,
        sp.description,
        c."Id",
        sp.costPrice,
        sp.salePrice,
        sp.suggestedPrice,
        CASE WHEN sp.salePrice <= 0 THEN 0 ELSE ROUND((sp.salePrice - sp.costPrice) / sp.salePrice, 4) END,
        sp.currentStock,
        sp.minimumStock,
        sp.itemsPerPlate,
        sp.estimatedPrintTimeMinutes,
        sp.estimatedWeightGrams,
        sp.lengthMetersUsed,
        sp.tariffPerKwh,
        sp.finishingPercentage,
        pp."Id",
        fp."Id",
        mf."Id",
        sp.createdAtUtc,
        sp.updatedAtUtc
    FROM _seed_products sp
    JOIN public."Categories" c ON c."Name" = sp.categoryName
    LEFT JOIN public."PrinterProfiles" pp ON pp."Name" = sp.printerName
    LEFT JOIN public."FilamentProfiles" fp ON fp."Name" = sp.filamentName
    LEFT JOIN public."MarketplaceFees" mf ON mf."Name" = sp.marketplaceName
    ON CONFLICT ("Sku") DO UPDATE SET
        "Name" = EXCLUDED."Name",
        "Description" = EXCLUDED."Description",
        "CategoryId" = EXCLUDED."CategoryId",
        "CostPrice" = EXCLUDED."CostPrice",
        "SalePrice" = EXCLUDED."SalePrice",
        "SuggestedPrice" = EXCLUDED."SuggestedPrice",
        "ProfitMargin" = EXCLUDED."ProfitMargin",
        "CurrentStock" = EXCLUDED."CurrentStock",
        "MinimumStock" = EXCLUDED."MinimumStock",
        "ItemsPerPlate" = EXCLUDED."ItemsPerPlate",
        "EstimatedPrintTimeMinutes" = EXCLUDED."EstimatedPrintTimeMinutes",
        "EstimatedWeightGrams" = EXCLUDED."EstimatedWeightGrams",
        "LengthMetersUsed" = EXCLUDED."LengthMetersUsed",
        "TariffPerKwh" = EXCLUDED."TariffPerKwh",
        "FinishingPercentage" = EXCLUDED."FinishingPercentage",
        "PrinterProfileId" = EXCLUDED."PrinterProfileId",
        "FilamentProfileId" = EXCLUDED."FilamentProfileId",
        "DefaultMarketplaceFeeId" = EXCLUDED."DefaultMarketplaceFeeId",
        "UpdatedAtUtc" = EXCLUDED."UpdatedAtUtc";

    INSERT INTO public."ProductRecipes" (
        "Id","ProductId","LaborHours","LaborCostPerHour","AdditionalCosts","WholesaleMarkup","RetailMarkup","ResellerMarkup","TotalCost","CreatedAtUtc","UpdatedAtUtc")
    SELECT
        sp.recipeId,
        p."Id",
        sp.laborHours,
        sp.laborCostPerHour,
        sp.additionalCosts,
        sp.wholesaleMarkup,
        sp.retailMarkup,
        sp.resellerMarkup,
        sp.compositionCost,
        sp.createdAtUtc,
        sp.updatedAtUtc
    FROM _seed_products sp
    JOIN public."Products" p ON p."Sku" = sp.sku
    ON CONFLICT ("ProductId") DO UPDATE SET
        "LaborHours" = EXCLUDED."LaborHours",
        "LaborCostPerHour" = EXCLUDED."LaborCostPerHour",
        "AdditionalCosts" = EXCLUDED."AdditionalCosts",
        "WholesaleMarkup" = EXCLUDED."WholesaleMarkup",
        "RetailMarkup" = EXCLUDED."RetailMarkup",
        "ResellerMarkup" = EXCLUDED."ResellerMarkup",
        "TotalCost" = EXCLUDED."TotalCost",
        "UpdatedAtUtc" = EXCLUDED."UpdatedAtUtc";

    DELETE FROM public."ProductRecipeItems" pri
    USING public."ProductRecipes" pr, public."Products" p, _seed_products sp
    WHERE pri."ProductRecipeId" = pr."Id"
      AND pr."ProductId" = p."Id"
      AND p."Sku" = sp.sku;

    INSERT INTO public."ProductRecipeItems" ("Id","ProductRecipeId","SupplyId","Quantity")
    SELECT
        sp.recipeItemId,
        pr."Id",
        su."Id",
        sp.recipeItemQuantity
    FROM _seed_products sp
    JOIN public."Products" p ON p."Sku" = sp.sku
    JOIN public."ProductRecipes" pr ON pr."ProductId" = p."Id"
    JOIN public."Supplies" su ON su."Name" = sp.filamentName
    WHERE sp.recipeItemQuantity > 0;

    END IF;
END $EF$;

