entstock":0.0,"minimumstock":2.0,"createdatutc":"2026-04-19T00:00:00Z","updatedatutc":"2026-04-19T00:00:00Z","costprice":6.3,"saleprice":15.76,"suggestedprice":15.76,"desiredmarkup":2.5,"itemsperplate":1,"estimatedprinttimeminutes":60.0,"estimatedweightgrams":12.3,"lengthmetersused":4.12,"tariffperkwh":0.95,"finishingpercentage":0.05,"printername":"BambuLab P1S","filamentname":"PLA - 120","marketplacename":"NENHUM","compositioncost":5.83,"laborhours":1.0,"laborcostperhour":0.5,"additionalcosts":3.0,"wholesalemarkup":2.0,"retailmarkup":2.5,"resellermarkup":2.5,"recipeitemquantity":12.3},{"id":"c5b5e56b-f8a8-5ff6-90cc-92e9b18c8873","recipeid":"fd1a392b-57d5-5069-b953-04f4652b8179","recipeitemid":"7b7109d5-1f41-5a50-aacd-f42317c4d2ec","name":"Coruxi","sku":"CALCULADORA-OVOS-CORUXI","description":"Produto extraido da planilha Calculadora Ovos","categoryname":"Calculadora Ovos","currentstock":0.0,"minimumstock":2.0,"createdatutc":"2026-04-19T00:00:00Z","updatedatutc":"2026-04-19T00:00:00Z","costprice":5.49,"saleprice":13.74,"suggestedprice":13.74,"desiredmarkup":2.5,"itemsperplate":1,"estimatedprinttimeminutes":45.85,"estimatedweightgrams":8.24,"lengthmetersused":2.76,"tariffperkwh":0.95,"finishingpercentage":0.05,"printername":"BambuLab P1S","filamentname":"PLA - 120","marketplacename":"NENHUM","compositioncost":5.13,"laborhours":1.0,"laborcostperhour":0.5,"additionalcosts":3.0,"wholesalemarkup":2.0,"retailmarkup":2.5,"resellermarkup":2.5,"recipeitemquantity":8.24},{"id":"5ace35da-94ed-5835-9b89-5e76edc78cd8","recipeid":"ffe2baf6-7507-5854-ab64-3ef061015ca4","recipeitemid":"5fa79fb6-bff3-5f11-a78d-388351bc3972","name":"Ovo Rosca","sku":"CALCULADORA-OVOS-OVO-ROSCA","description":"Produto extraido da planilha Calculadora Ovos","categoryname":"Calculadora Ovos","currentstock":0.0,"minimumstock":2.0,"createdatutc":"2026-04-19T00:00:00Z","updatedatutc":"2026-04-19T00:00:00Z","costprice":7.55,"saleprice":18.87,"suggestedprice":18.87,"desiredmarkup":2.5,"itemsperplate":1,"estimatedprinttimeminutes":70.0,"estimatedweightgrams":21.0,"lengthmetersused":7.0,"tariffperkwh":0.95,"finishingpercentage":0.02,"printername":"BambuLab P1S","filamentname":"PLA - 120","marketplacename":"NENHUM","compositioncost":7.0,"laborhours":1.0,"laborcostperhour":0.5,"additionalcosts":3.0,"wholesalemarkup":2.0,"retailmarkup":2.5,"resellermarkup":2.5,"recipeitemquantity":21.0}]$json$ AS jsonb)) AS x(
        id uuid,
        recipeId uuid,
        recipeItemId uuid,
        name text,
        sku text,
        description text,
        categoryName text,
        costPrice numeric,
        salePrice numeric,
        suggestedPrice numeric,
        desiredMarkup numeric,
        currentStock numeric,
        minimumStock numeric,
        estimatedPrintTimeMinutes numeric,
        estimatedWeightGrams numeric,
        lengthMetersUsed numeric,
        tariffPerKwh numeric,
        finishingPercentage numeric,
        printerName text,
        filamentName text,
        marketplaceName text,
        compositionCost numeric,
        laborHours numeric,
        laborCostPerHour numeric,
        additionalCosts numeric,
        wholesaleMarkup numeric,
        retailMarkup numeric,
        resellerMarkup numeric,
        itemsPerPlate integer,
        recipeItemQuantity numeric,
        createdAtUtc timestamptz,
        updatedAtUtc timestamptz
    );

    INSERT INTO public."Products" (
        "Id","Name","Sku","Description","CategoryId","CostPrice","SalePrice","SuggestedPrice","ProfitMargin","CurrentStock","MinimumStock",
        "ItemsPerPlate","EstimatedPrintTimeMinutes","EstimatedWeightGrams","LengthMetersUsed","TariffPerKwh","FinishingPercentage","PrinterProfileId","FilamentProfileId",
        "DefaultMarketplaceFeeId","CreatedAtUtc","UpdatedAtUtc")
    SELECT
        sp.id,
        sp.name,
        sp.sku,
        sp.description,
        c."Id",
        sp.costPrice,
        sp.salePrice,
        sp.suggestedPrice,
        CASE WHEN sp.salePrice <= 0 THEN 0 ELSE ROUND((sp.salePrice - sp.costPrice) / sp.salePrice, 4) END,
        sp.currentStock,
        sp.minimumStock,
        sp.itemsPerPlate,
        sp.estimatedPrintTimeMinutes,
        sp.estimatedWeightGrams,
        sp.lengthMetersUsed,
        sp.tariffPerKwh,
        sp.finishingPercentage,
        pp."Id",
        fp."Id",
        mf."Id",
        sp.createdAtUtc,
        sp.updatedAtUtc
    FROM _seed_products sp
    JOIN public."Categories" c ON c."Name" = sp.categoryName
    LEFT JOIN public."PrinterProfiles" pp ON pp."Name" = sp.printerName
    LEFT JOIN public."FilamentProfiles" fp ON fp."Name" = sp.filamentName
    LEFT JOIN public."MarketplaceFees" mf ON mf."Name" = sp.marketplaceName
    ON CONFLICT ("Sku") DO UPDATE SET
        "Name" = EXCLUDED."Name",
        "Description" = EXCLUDED."Description",
        "CategoryId" = EXCLUDED."CategoryId",
        "CostPrice" = EXCLUDED."CostPrice",
        "SalePrice" = EXCLUDED."SalePrice",
        "SuggestedPrice" = EXCLUDED."SuggestedPrice",
        "ProfitMargin" = EXCLUDED."ProfitMargin",
        "CurrentStock" = EXCLUDED."CurrentStock",
        "MinimumStock" = EXCLUDED."MinimumStock",
        "ItemsPerPlate" = EXCLUDED."ItemsPerPlate",
        "EstimatedPrintTimeMinutes" = EXCLUDED."EstimatedPrintTimeMinutes",
        "EstimatedWeightGrams" = EXCLUDED."EstimatedWeightGrams",
        "LengthMetersUsed" = EXCLUDED."LengthMetersUsed",
        "TariffPerKwh" = EXCLUDED."TariffPerKwh",
        "FinishingPercentage" = EXCLUDED."FinishingPercentage",
        "PrinterProfileId" = EXCLUDED."PrinterProfileId",
        "FilamentProfileId" = EXCLUDED."FilamentProfileId",
        "DefaultMarketplaceFeeId" = EXCLUDED."DefaultMarketplaceFeeId",
        "UpdatedAtUtc" = EXCLUDED."UpdatedAtUtc";

    INSERT INTO public."ProductRecipes" (
        "Id","ProductId","LaborHours","LaborCostPerHour","AdditionalCosts","WholesaleMarkup","RetailMarkup","ResellerMarkup","TotalCost","CreatedAtUtc","UpdatedAtUtc")
    SELECT
        sp.recipeId,
        p."Id",
        sp.laborHours,
        sp.laborCostPerHour,
        sp.additionalCosts,
        sp.wholesaleMarkup,
        sp.retailMarkup,
        sp.resellerMarkup,
        sp.compositionCost,
        sp.createdAtUtc,
        sp.updatedAtUtc
    FROM _seed_products sp
    JOIN public."Products" p ON p."Sku" = sp.sku
    ON CONFLICT ("ProductId") DO UPDATE SET
        "LaborHours" = EXCLUDED."LaborHours",
        "LaborCostPerHour" = EXCLUDED."LaborCostPerHour",
        "AdditionalCosts" = EXCLUDED."AdditionalCosts",
        "WholesaleMarkup" = EXCLUDED."WholesaleMarkup",
        "RetailMarkup" = EXCLUDED."RetailMarkup",
        "ResellerMarkup" = EXCLUDED."ResellerMarkup",
        "TotalCost" = EXCLUDED."TotalCost",
        "UpdatedAtUtc" = EXCLUDED."UpdatedAtUtc";

    DELETE FROM public."ProductRecipeItems" pri
    USING public."ProductRecipes" pr, public."Products" p, _seed_products sp
    WHERE pri."ProductRecipeId" = pr."Id"
      AND pr."ProductId" = p."Id"
      AND p."Sku" = sp.sku;

    INSERT INTO public."ProductRecipeItems" ("Id","ProductRecipeId","SupplyId","Quantity")
    SELECT
        sp.recipeItemId,
        pr."Id",
        su."Id",
        sp.recipeItemQuantity
    FROM _seed_products sp
    JOIN public."Products" p ON p."Sku" = sp.sku
    JOIN public."ProductRecipes" pr ON pr."ProductId" = p."Id"
    JOIN public."Supplies" su ON su."Name" = sp.filamentName
    WHERE sp.recipeItemQuantity > 0;

    END IF;
END $EF$;

