DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260420231425_AddNumericCategoryAndProductIdentifiers') THEN
    ALTER TABLE public."Products" ADD "NumericIdentifier" integer NOT NULL DEFAULT 0;
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260420231425_AddNumericCategoryAndProductIdentifiers') THEN
    ALTER TABLE public."Categories" ADD "NumericIdentifier" integer NOT NULL DEFAULT 0;
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260420231425_AddNumericCategoryAndProductIdentifiers') THEN
    WITH ordered_categories AS (
        SELECT "Id", ROW_NUMBER() OVER (ORDER BY "Name", "Id") AS numeric_identifier
        FROM public."Categories"
    )
    UPDATE public."Categories" AS category
    SET "NumericIdentifier" = ordered_categories.numeric_identifier
    FROM ordered_categories
    WHERE category."Id" = ordered_categories."Id";
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260420231425_AddNumericCategoryAndProductIdentifiers') THEN
    WITH ordered_products AS (
        SELECT "Id", ROW_NUMBER() OVER (ORDER BY "Name", "Id") AS numeric_identifier
        FROM public."Products"
    )
    UPDATE public."Products" AS product
    SET "NumericIdentifier" = ordered_products.numeric_identifier
    FROM ordered_products
    WHERE product."Id" = ordered_products."Id";
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260420231425_AddNumericCategoryAndProductIdentifiers') THEN
    UPDATE public."Products" AS product
    SET "Sku" = LPAD(category."NumericIdentifier"::text, 5, '0') || '-' || LPAD(product."NumericIdentifier"::text, 8, '0')
    FROM public."Categories" AS category
    WHERE product."CategoryId" = category."Id";
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260420231425_AddNumericCategoryAndProductIdentifiers') THEN
    CREATE UNIQUE INDEX "IX_Products_NumericIdentifier" ON public."Products" ("NumericIdentifier");
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260420231425_AddNumericCategoryAndProductIdentifiers') THEN
